timestamp: "2025-01-01T00:00:00Z"
sessionId: sess_abc123
turnId: turn_abc123
runId: run_abc123

""";

        var instance = EngineEvent.FromYaml(yamlData);

        Assert.NotNull(instance);
        Assert.Equal("evt_abc123", instance.Id);
        Assert.Equal("2025-01-01T00:00:00Z", instance.Timestamp);
        Assert.Equal("sess_abc123", instance.SessionId);
        Assert.Equal("turn_abc123", instance.TurnId);
        Assert.Equal("run_abc123", instance.RunId);
    }

