    [Fact]
    public void RoundtripJson()
    {
        // Test that FromJson -> ToJson -> FromJson produces equivalent data
        string jsonData = """
{
  "id": "evt_abc123",
  "timestamp": "2025-01-01T00:00:00Z",
  "sessionId": "sess_abc123",
  "turnId": "turn_abc123",
  "runId": "run_abc123"
}
""";

        var original = EngineEvent.FromJson(jsonData);
        Assert.NotNull(original);

        var json = original.ToJson();
        Assert.False(string.IsNullOrEmpty(json));

        var reloaded = EngineEvent.FromJson(json);
        Assert.NotNull(reloaded);
        Assert.Equal("evt_abc123", reloaded.Id);
        Assert.Equal("2025-01-01T00:00:00Z", reloaded.Timestamp);
        Assert.Equal("sess_abc123", reloaded.SessionId);
        Assert.Equal("turn_abc123", reloaded.TurnId);
        Assert.Equal("run_abc123", reloaded.RunId);
    }

